// Парсим JSON-ответ от Claude. Возвращаем плоский объект — поля колонок на верхнем уровне для autoMap в Sheets.
const raw = $input.first().json;
let text = '';
try { text = raw.content[0].text || ''; } catch (e) { text = ''; }

// Иногда Claude всё равно оборачивает в ```json``` — снимем.
text = text.replace(/```json\s*/i, '').replace(/```\s*$/, '').trim();

let parsed;
try { parsed = JSON.parse(text); }
catch (e) { parsed = { intent: 'unknown', _parse_error: text.slice(0, 200) }; }

const chatId = $('Конфиг').item.json.chat_id;

if (parsed.intent !== 'reminder' || !parsed.next_date || !parsed.title) {
  return [{
    json: {
      action: 'reply_only',
      chat_id: chatId,
      reply_text: '🤔 Не понял как создать напоминание. Напиши в формате:\n\n• «30 мая — сдать анализы»\n• «через неделю — стоматолог»\n• «каждый понедельник — взвеситься»\n• «раз в 14 дней — стирать постельное»',
    }
  }];
}

const slug = parsed.title.toLowerCase().replace(/[^a-zа-яё0-9]+/gi, '-').replace(/-+/g, '-').replace(/^-|-$/g, '').slice(0, 30);
const reminderId = slug + '-' + Date.now().toString(36);

return [{
  json: {
    action: 'add_reminder',
    chat_id: chatId,
    reply_text: `✅ Запомнила:\n*${parsed.title}*\nна *${parsed.next_date}* (${String(parsed.frequency || 'once')})`,
    // Поля для Sheets — на верхнем уровне для autoMap:
    reminder_id: reminderId,
    title: parsed.title,
    description: parsed.description || '',
    next_date: parsed.next_date,
    frequency: String(parsed.frequency || 'once'),
    enabled: 'TRUE',
    last_sent: '',
  }
}];

// Пропускаем дальше только если action=add_reminder.
// Поля row теперь плоские (на верхнем уровне) — это нужно для autoMapInputData в Sheets.
const item = $input.first().json;
if (item && item.action === 'add_reminder' && item.reminder_id) {
  return [{ json: item }];
}
return [];
